# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, NotFoundError
import os

app = Flask(__name__)

# Configuration
ELASTICSEARCH_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ELASTICSEARCH_PORT = os.environ.get('ELASTICSEARCH_PORT', '9200')
ELASTICSEARCH_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')

# Initialize Elasticsearch client
try:
    es_client = Elasticsearch(
        [f"http://{ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}"],
        timeout=30, # Increased timeout for potentially heavier search operations
        max_retries=10, # More retries for transient network issues
        retry_on_timeout=True
    )
    # Ping to check connection
    if not es_client.ping():
        raise ValueError("Connection to Elasticsearch failed!")
    print("Successfully connected to Elasticsearch.")
except Exception as e:
    print(f"Error connecting to Elasticsearch: {e}")
    # Depending on the application, you might want to exit or log more severely
    # For now, we'll continue but search requests will fail.
    es_client = None

@app.route('/api/search', methods=['GET'])
def search_products():
    if not es_client:
        return jsonify({"error": "Search service is unavailable. Elasticsearch connection failed."}), 503

    query = request.args.get('q', '').strip()

    if not query:
        return jsonify({"error": "Query parameter 'q' is required."}), 400

    try:
        # Build Elasticsearch query
        # Using a multi_match query for broader search across relevant fields
        # 'best_fields' type is good for searching different fields with different contents
        # 'fuzziness' can help with typos, consider its performance impact
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "fields": ["name^3", "description^1", "category^2", "tags^1.5"], # Boost important fields
                    "type": "best_fields",
                    "fuzziness": "AUTO" # Automatically determine fuzziness based on term length
                }
            },
            "highlight": { # Add highlighting for better UX, showing where keywords matched
                "fields": {
                    "name": {},
                    "description": {}
                },
                "pre_tags": ["<em>"],
                "post_tags": ["</em>"]
            },
            "size": 20, # Default number of results, can be made configurable
            "from": 0   # Pagination support, can be made configurable
        }

        # Execute search query
        res = es_client.search(index=ELASTICSEARCH_INDEX, body=search_body)

        products = []
        for hit in res['hits']['hits']:
            product = hit['_source']
            product['id'] = hit['_id'] # Add Elasticsearch document ID
            product['score'] = hit['_score'] # Add relevance score
            product['highlight'] = hit.get('highlight', {}) # Add highlighting snippets
            products.append(product)

        return jsonify({
            "query": query,
            "total_results": res['hits']['total']['value'],
            "products": products
        }), 200

    except NotFoundError:
        return jsonify({"error": f"Index '{ELASTICSEARCH_INDEX}' not found."}), 500
    except Exception as e:
        print(f"Elasticsearch search error: {e}")
        return jsonify({"error": "An internal server error occurred during the search."}), 500

if __name__ == '__main__':
    # For production, use a WSGI server like Gunicorn
    # For development, run with Flask's built-in server
    app.run(debug=os.environ.get('FLASK_DEBUG', 'True') == 'True',
            host='0.0.0.0',
            port=int(os.environ.get('FLASK_PORT', 5000)))